import{_ as a,o as s,c as t,ae as l}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"GitHub Copilot","description":"장치 흐름을 사용하여 OpenClaw에서 GitHub Copilot에 로그인","frontmatter":{"title":"GitHub Copilot","description":"장치 흐름을 사용하여 OpenClaw에서 GitHub Copilot에 로그인"},"headers":[],"relativePath":"providers/github-copilot.md","filePath":"providers/github-copilot.md","lastUpdated":null}'),o={name:"providers/github-copilot.md"};function e(p,i,h,n,d,r){return s(),t("div",null,[...i[0]||(i[0]=[l('<h1 id="github-copilot" tabindex="-1">GitHub Copilot <a class="header-anchor" href="#github-copilot" aria-label="Permalink to &quot;GitHub Copilot&quot;">​</a></h1><h2 id="github-copilot이란" tabindex="-1">GitHub Copilot이란? <a class="header-anchor" href="#github-copilot이란" aria-label="Permalink to &quot;GitHub Copilot이란?&quot;">​</a></h2><p>GitHub Copilot은 GitHub의 AI 코딩 어시스턴트입니다. GitHub 계정 및 플랜에 대한 Copilot 모델에 액세스할 수 있습니다. OpenClaw는 두 가지 방법으로 Copilot을 모델 프로바이더로 사용할 수 있습니다.</p><h2 id="openclaw에서-copilot을-사용하는-두-가지-방법" tabindex="-1">OpenClaw에서 Copilot을 사용하는 두 가지 방법 <a class="header-anchor" href="#openclaw에서-copilot을-사용하는-두-가지-방법" aria-label="Permalink to &quot;OpenClaw에서 Copilot을 사용하는 두 가지 방법&quot;">​</a></h2><h3 id="_1-내장-github-copilot-프로바이더-github-copilot" tabindex="-1">1) 내장 GitHub Copilot 프로바이더 (<code>github-copilot</code>) <a class="header-anchor" href="#_1-내장-github-copilot-프로바이더-github-copilot" aria-label="Permalink to &quot;1) 내장 GitHub Copilot 프로바이더 (`github-copilot`)&quot;">​</a></h3><p>네이티브 장치 로그인 흐름을 사용하여 GitHub 토큰을 받은 후 OpenClaw 실행 시 Copilot API 토큰으로 교환합니다. VS Code가 필요하지 않기 때문에 이것이 <strong>기본</strong> 및 가장 간단한 경로입니다.</p><h3 id="_2-copilot-proxy-플러그인-copilot-proxy" tabindex="-1">2) Copilot Proxy 플러그인 (<code>copilot-proxy</code>) <a class="header-anchor" href="#_2-copilot-proxy-플러그인-copilot-proxy" aria-label="Permalink to &quot;2) Copilot Proxy 플러그인 (`copilot-proxy`)&quot;">​</a></h3><p><strong>Copilot Proxy</strong> VS Code 확장을 로컬 브리지로 사용합니다. OpenClaw는 프록시의 <code>/v1</code> 엔드포인트와 통신하며 구성한 모델 목록을 사용합니다. VS Code에서 이미 Copilot Proxy를 실행 중이거나 이를 통해 라우팅해야 할 때 선택하십시오. 플러그인을 활성화하고 VS Code 확장을 실행 상태로 유지해야 합니다.</p><p>GitHub Copilot을 모델 프로바이더(<code>github-copilot</code>)로 사용하십시오. 로그인 명령은 GitHub 장치 흐름을 실행하고, 인증 프로필을 저장하며, 해당 프로필을 사용하도록 구성을 업데이트합니다.</p><h2 id="cli-설정" tabindex="-1">CLI 설정 <a class="header-anchor" href="#cli-설정" aria-label="Permalink to &quot;CLI 설정&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login-github-copilot</span></span></code></pre></div><p>URL을 방문하고 일회용 코드를 입력하라는 메시지가 표시됩니다. 완료될 때까지 터미널을 열어두십시오.</p><h3 id="선택적-플래그" tabindex="-1">선택적 플래그 <a class="header-anchor" href="#선택적-플래그" aria-label="Permalink to &quot;선택적 플래그&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login-github-copilot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --yes</span></span></code></pre></div><p>한 번에 프로바이더의 권장 기본 모델도 적용하려면 대신 일반 인증 명령을 사용하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github-copilot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --method</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> device</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-default</span></span></code></pre></div><h2 id="기본-모델-설정" tabindex="-1">기본 모델 설정 <a class="header-anchor" href="#기본-모델-설정" aria-label="Permalink to &quot;기본 모델 설정&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github-copilot/gpt-4o</span></span></code></pre></div><h3 id="구성-스니펫" tabindex="-1">구성 스니펫 <a class="header-anchor" href="#구성-스니펫" aria-label="Permalink to &quot;구성 스니펫&quot;">​</a></h3><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">primary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github-copilot/gpt-4o&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } } },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="참고-사항" tabindex="-1">참고 사항 <a class="header-anchor" href="#참고-사항" aria-label="Permalink to &quot;참고 사항&quot;">​</a></h2><ul><li>대화형 TTY가 필요합니다; 터미널에서 직접 실행하십시오.</li><li>Copilot 모델 가용성은 플랜에 따라 다릅니다; 모델이 거부되면 다른 ID를 시도하십시오 (예: <code>github-copilot/gpt-4.1</code>).</li><li>Claude 모델 ID는 Anthropic Messages 전송을 자동으로 사용합니다; GPT, o-시리즈, Gemini 모델은 OpenAI Responses 전송을 유지합니다.</li><li>로그인은 인증 프로필 저장소에 GitHub 토큰을 저장하고 OpenClaw 실행 시 Copilot API 토큰으로 교환합니다.</li></ul>',22)])])}const u=a(o,[["render",e]]);export{k as __pageData,u as default};
